interface ServerState {
  env: "production" | "development";
  hasWorkspaceFolderCapability: boolean;

  telemetryEnabled: boolean;

  connection: Connection;
  documents: TextDocuments<TextDocument>;
  indexedWorkspaceFolders: WorkspaceFolder[];
  projects: SolProjectMap;
  solFileIndex: SolFileIndexMap;

  telemetry: Telemetry;
  logger: Logger;
  solcVersions: string[];

  // Associate validation request ids to files to solve parallel validation jobs on the same file
  validationCount: number;
  lastValidationId: { [uri: string]: number };
  workspaceFileRetriever: WorkspaceFileRetriever;
  cachedCompilerInfo: {
    [solcVersion: string]: { isSolcJs: boolean; compilerPath: string };
  };
  shownInitializationError: Record<string, boolean>;
  extensionConfig: {
    formatter?: string;
  };
}

interface RemappedNpmPackagesGraphJson {
  readonly hardhatProjectPackage: ResolvedNpmPackage;
  readonly packageByInputSourceNameRoot: Readonly<
    Record<string, ResolvedNpmPackage>
  >;
  readonly installationMap: Readonly<
    Record<
      string,
      Readonly<
        Record<
          InstallationName,
          {
            readonly package: ResolvedNpmPackage;
            readonly generatedRemapping: Remapping;
          }
        >
      >
    >
  >;
  readonly userRemappingsPerPackage: Record<
    string,
    ReadonlyArray<ResolvedUserRemapping | UnresolvedNpmUserRemapping>
  >;
  readonly generatedRemappingsIntoNpmFiles: Readonly<
    Record<string, Readonly<Record<string, Remapping>>>
  >;
}

interface EdrNetworkConfig {
  type: "edr-simulated";
  accounts: EdrNetworkAccountsConfig;
  chainId: number;
  chainType?: ChainType;
  from?: string;
  gas: GasConfig;
  gasMultiplier: number;
  gasPrice: GasConfig;

  // EDR network specific
  allowBlocksWithSameTimestamp: boolean;
  allowUnlimitedContractSize?: boolean;
  blockGasLimit?: bigint | false;
  coinbase: Uint8Array;
  forking?: EdrNetworkForkingConfig;
  hardfork: string;
  initialBaseFeePerGas?: bigint;
  initialDate: string | Date;
  loggingEnabled: boolean;
  minGasPrice: bigint;
  mining: EdrNetworkMiningConfig;
  networkId: number;
  throwOnCallFailures: boolean;
  throwOnTransactionFailures: boolean;
  transactionGasCap?: bigint | false;
}

const matchingRelativeWorkspacePaths = (
    await Promise.all(
      template.files.map(async (relativeTemplatePath) => {
        const relativeWorkspacePath =
          relativeTemplateToWorkspacePath(relativeTemplatePath);

        const absoluteWorkspacePath = path.join(
          workspace,
          relativeWorkspacePath,
        );

        if (!(await exists(absoluteWorkspacePath))) {
          return undefined;
        }

        // We ignore directories in this clash detection
        if (await isDirectory(absoluteWorkspacePath)) {
          return undefined;
        }

        return relativeWorkspacePath;
      }),
    )
  ).filter((relativeWorkspacePath) => relativeWorkspacePath !== undefined);

if (receipt !== undefined) {
  // There's a slight race condition here that we won't check.
  //
  // We should be checking that the receipt's block hash is still part
  // of the chain, as it could have been reorged out.
  //
  // As we intend to use this with requiredConfirmations with
  // values that are high enough to avoid reorgs, we don't do it.
  const confirmations = block.number - receipt.blockNumber + 1;

  if (confirmations >= params.requiredConfirmations) {
    return {
      type: JournalMessageType.TRANSACTION_CONFIRM,
      futureId: params.exState.id,
      networkInteractionId: lastNetworkInteraction.id,
      hash: transaction.hash,
      receipt,
    };
  }

  return undefined;
}

class NamedContractDeploymentFutureImplementation<
    ContractNameT extends string,
  >
  extends BaseFutureImplementation<FutureType.NAMED_ARTIFACT_CONTRACT_DEPLOYMENT>
  implements NamedArtifactContractDeploymentFuture<ContractNameT>
{
  constructor(
    public override readonly id: string,
    public override readonly module: IgnitionModuleImplementation,
    public readonly contractName: ContractNameT,
    public readonly constructorArgs: ArgumentType[],
    public readonly libraries: Record<string, ContractFuture<string>>,
    public readonly value:
      | bigint
      | ModuleParameterRuntimeValue<bigint>
      | StaticCallFuture<string, string>
      | ReadEventArgumentFuture,
    public readonly from: string | AccountRuntimeValue | undefined,
  ) {
    super(id, FutureType.NAMED_ARTIFACT_CONTRACT_DEPLOYMENT, module);
  }
}

class ArtifactContractDeploymentFutureImplementation<
    ContractNameT extends string,
  >
  extends BaseFutureImplementation<FutureType.CONTRACT_DEPLOYMENT>
  implements ContractDeploymentFuture
{
  constructor(
    public override readonly id: string,
    public override readonly module: IgnitionModuleImplementation,
    public readonly contractName: ContractNameT,
    public readonly constructorArgs: ArgumentType[],
    public readonly artifact: Artifact,
    public readonly libraries: Record<string, ContractFuture<string>>,
    public readonly value:
      | bigint
      | ModuleParameterRuntimeValue<bigint>
      | StaticCallFuture<string, string>
      | ReadEventArgumentFuture,
    public readonly from: string | AccountRuntimeValue | undefined,
  ) {
    super(id, FutureType.CONTRACT_DEPLOYMENT, module);
  }
}

class NamedContractCallFutureImplementation<
    ContractNameT extends string,
    FunctionNameT extends string,
  >
  extends BaseFutureImplementation<FutureType.CONTRACT_CALL>
